  edmonton: { slug: "edmonton", name: "Edmonton", state: "Alberta", country: "Canada", region: "Edmonton, St. Albert, Sherwood Park, and the greater Edmonton metropolitan area", description: "Alberta's capital city and a major hub for oil, tech, and innovation", landmarks: ["Downtown Edmonton", "Whyte Avenue", "West Edmonton Mall", "Ice District", "104 Street NW"], industries: ["oil & gas", "tech startups", "government", "construction", "agriculture", "healthcare", "education", "logistics"], coordinates: { latitude: 53.5461, longitude: -113.4937 }, uniqueContent: ["Edmonton is home to TML Agency's Canadian headquarters, delivering Alberta-focused digital marketing with deep understanding of the local market. We serve businesses across Alberta including Calgary, Red Deer, and Fort McMurray with competitive pricing and dedicated support.", "As Alberta's capital, Edmonton's economy is diversifying rapidly from oil & gas into tech, clean energy, and innovation. Businesses here need digital marketing partners who understand both the traditional industries and the emerging startup ecosystem.", "Our team provides bilingual support (English/Punjabi) and understands the unique cultural landscape of Alberta's business community. From Ice District developments to Whyte Avenue retail, we help Edmonton businesses compete digitally."], population: 1100000, businessCount: "55,000+", avgIncome: "C$68,000", topEmployers: ["Government of Alberta", "University of Alberta", "Alberta Health Services", "Stantec", "PCL Construction"], economicGrowthRate: "3.5%", digitalAdoptionRate: "85%", currency: "CAD", cityTier: 1, marketSize: "Large" },
  calgary: { slug: "calgary", name: "Calgary", state: "Alberta", country: "Canada", region: "Calgary, Airdrie, Cochrane, and southern Alberta", description: "Canada's energy capital and a growing tech hub", landmarks: ["Downtown Calgary", "Stephen Avenue", "Kensington", "Beltline", "University District"], industries: ["oil & gas", "finance", "tech", "agriculture", "tourism", "construction", "film"], coordinates: { latitude: 51.0447, longitude: -114.0719 }, uniqueContent: ["Calgary's energy sector is the backbone of Alberta's economy, but the city's tech corridor along Stephen Avenue and the Beltline is growing fast. TML helps Calgary businesses bridge the gap between traditional oil & gas marketing and modern digital-first strategies that attract talent and clients.", "The Calgary market is fiercely competitive, with businesses on Stephen Avenue, in Kensington, and across the Beltline all vying for the same digitally engaged consumer. Our geo-targeted campaigns and local SEO strategies ensure your Calgary business appears exactly where your customers are searching.", "From our Edmonton office, TML serves Calgary clients with deep Alberta market understanding and dedicated account management. We know Calgary's boom-and-bust cycles, the Stampede marketing window, and how to position brands for both the energy executive in the Bow Tower and the creative entrepreneur in the East Village."], population: 1400000, businessCount: "65,000+", avgIncome: "C$72,000", topEmployers: ["Canadian Pacific Kansas City", "Suncor Energy", "TC Energy", "Shaw Communications", "University of Calgary"], economicGrowthRate: "3.5%", digitalAdoptionRate: "88%", currency: "CAD", cityTier: 1, marketSize: "Large" },
